class Solution {
    public int minSteps(int n) {
        int operations = 0;
        int divisor = 2;
        while (n > 1) {
            while (n % divisor == 0) {
                operations += divisor;
                n /= divisor;
            }
            divisor++;
        }
        return operations;
    }
}
